${issue.description ?? ""}`, labels: ["copilot-remediate"], assignees: ["copilot"], }), }, ); return new Response(await res.text(), { status: res.status }); }, }; # .github/workflows/scanner-to-copilot.yml name: Scanner → Copilot coding agent on: repository_dispatch: types: [security-finding] permissions: issues: write jobs: open-issue: runs-on: ubuntu-latest steps: - name: Create labeled issue for Copilot env: GH_TOKEN: ${{ secrets.GITHUB_TOKEN }} FINDING_ID: ${{ github.event.client_payload.finding_id }} FINDING_BODY: ${{ github.event.client_payload.description }} run: | gh issue create \ --repo ${{ github.repository }} \ --title "Remediate ${FINDING_ID}" \ --body "${FINDING_BODY}" \ --label copilot-remediate \ --assignee copilot Your scanner POSTs to /repos/{owner}/{repo}/dispatches with event_type: security-finding — the workflow fans it out into a labeled issue assigned to @copilot. Works the same for Snyk, Wiz, Semgrep, or any tool with a webhook.
# .github/workflows/nightly-copilot-sweep.yml name: Nightly Copilot remediation sweep on: schedule: - cron: "0 2 * * *" workflow_dispatch: permissions: issues: write security-events: read jobs: sweep: runs-on: ubuntu-latest steps: - name: Open issues for top-N open alerts env: GH_TOKEN: ${{ secrets.GITHUB_TOKEN }} run: | gh api "/repos/${{ github.repository }}/code-scanning/alerts?state=open&severity=error" \ --jq '.[0:5][] | {rule: .rule.id, number: .number, desc: .rule.description}' \ | while read -r row; do FID=$(echo "$row" | jq -r '.number') DESC=$(echo "$row" | jq -r '.desc') gh issue create \ --repo ${{ github.repository }} \ --title "Remediate CodeQL alert #${FID}" \ --body "$DESC" \ --label copilot-remediate \ --assignee copilot done Caps the queue: at most 5 Copilot PRs per night while the reviewer team is calibrating volume.

